  /// "Overflow | icmp pred X, C2 +/- C1".
  const WithOverflowInst *WO;
  const Value *WOV;
  const APInt *C1, *C2;
  if (match(&I, m_c_Or(m_CombineAnd(m_ExtractValue<1>(m_CombineAnd(
