  /// Try to canonicalize the pattern "Overflow | icmp u(pred) Res, C2" into
  /// a compare of X when the compare threshold is in the top partial product
  /// range that is covered by overflow.
  if (match(&I, m_c_Or(m_CombineAnd(m_ExtractValue<1>(m_CombineAnd(
                                        m_WithOverflowInst(WO), m_Value(WOV))),
                                    m_Value(Ov)),
                       m_OneUse(m_ICmp(Pred, m_ExtractValue<0>(m_Deferred(WOV)),
                                       m_APInt(C2))))) &&
      WO->getBinaryOp() == Instruction::Mul && !WO->isSigned() &&
      ICmpInst::isUnsigned(Pred) && match(WO->getRHS(), m_APInt(C1)) &&
      !C1->isZero()) {
    APInt Max = APInt::getAllOnes(C1->getBitWidth());
    APInt Quot = C2->udiv(*C1);
    APInt Rem = C2->urem(*C1);
    APInt NewC = Quot - APInt(C1->getBitWidth(), Rem.isZero() ? 1 : 0);

    bool Valid = false;
    switch (Pred) {
    case ICmpInst::ICMP_UGT:
      Valid = Quot != Max;
      break;
    case ICmpInst::ICMP_UGE:
      Valid = true;
      break;
    case ICmpInst::ICMP_ULT:
      Valid = Quot != Max;
      break;
    case ICmpInst::ICMP_ULE:
      Valid = true;
      break;
    default:
      break;
    }

    if (Valid) {
      Value *NewCmp = Builder.CreateICmp(
          Pred, WO->getLHS(), ConstantInt::get(WO->getLHS()->getType(), NewC));
      return replaceInstUsesWith(I, NewCmp);
    }
  }
